function largestPrimeFactor(n) {
  let largest = -1;

  // Remove all factors of 2
  while (n % 2 === 0) {
    largest = 2;
    n = n / 2;
  }

  // Check odd factors from 3 onwards
  for (let i = 3; i * i <= n; i += 2) {
    while (n % i === 0) {
      largest = i;
      n = n / i;
    }
  }

  // If n is still > 1, then it's a prime factor
  if (n > 1) largest = n;

  return largest;
}
